import React from "react";
import "./MainContent.scss";
import { Switch, Route, useLocation, useHistory } from "react-router-dom";
import routes from "../../routers/routers";
import routeKey from "../../constants/routeKeys";
import config from "../../constants/config";
import { useSelector } from "react-redux";
import { TRootState } from "../../redux/models/root.state";
import { TAppState } from "../../redux/models/app.state";
import bg_img from "../../assets/images/background_img.jpg";
import { Container } from "react-bootstrap";

export default () => {
  const { pathname } = useLocation();
  const histroy = useHistory();
  const mainContentRoutes = routes.find(r => r.routeKey === routeKey.mainContent);
  const { leftMenuIsOpen } = useSelector<TRootState, TAppState>(state => state.app);

  if (pathname === "/") {
    histroy.push("/about");
  }

  return (

    <div className="main-content" style={{
      marginLeft: leftMenuIsOpen ?
        config.leftMenuWidth :
        config.collapsedMenuWidth,
      backgroundImage: `url("${bg_img}")`
    }}>
      <Container>
        {(mainContentRoutes && mainContentRoutes.routes) &&
          <Switch>
            {mainContentRoutes.routes.map(r => (
              <Route
                key={r.routeKey}
                path={r.path}
                component={r.component}
                exact={r.exact}
              />)
            )}
          </Switch>
        }
      </Container>
    </div>

  )
}